scwin.sDate;
scwin.strCurDate;
scwin.strQryStDt;
scwin.isFilter;

scwin.onpageload = function() {
    scwin.sDate = $c.date.getServerDateTime("yyyyMMdd");
	scwin.strCurDate = scwin.sDate;	
	scwin.strQryStDt = scwin.strCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
    scwin.isFilter 	= true;

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        ica_adptYm.setValue(scwin.strQryStDt);
        ica_qryConDtFm.setValue(scwin.strQryStDt);
        ica_qryConDtTo.setValue(scwin.strCurDate);	
        acb_qryConKnd.setValue("YM");

        ed_homeClntNo.focus();

        $c.gus.cfDisableBtn([btn_save, btn_delete]);

        // $p.setTimeout(function() {
        //     ed_homeClntNo.setValue("227930");
        //     ica_adptYm.setValue("201102");

        //     ed_homeClntNo.focus();
        //     ed_homeClntNo.blur();

        //     ica_qryConDtFm.setValue("20110201");
        //     ica_qryConDtTo.setValue("20110228");	
        // }, {"delay":50});

    }, {"delay":50});
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    //validation check
    if (acb_qryConKnd.getValue() == "YM"){
        if (!await $c.gus.cfValidate([ed_homeClntNo, ica_adptYm])){
            return;
        }		
    } else {
        if (!await $c.gus.cfValidate([ed_homeClntNo, ica_qryConDtFm, ica_qryConDtTo])){
            return;
        }

        //조회시작일자가 더 클경우 체크
        if (!await $c.gus.cfIsAfterDate(ica_qryConDtFm.getValue(), ica_qryConDtTo.getValue())) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            return;
        }		
    }
    $c.sbm.execute(sbm_retrieve);

};

//-------------------------------------------------------------------------
// 조회조건 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search, null);
    ica_adptYm.setValue(scwin.strQryStDt);
    ica_qryConDtFm.setValue(scwin.strQryStDt);
    ica_qryConDtTo.setValue(scwin.strCurDate);
    acb_qryConKnd.setValue("YM");

    ed_homeClntNo.focus();
};

