    // ds_saveDetail.removeAll() ;
    // var	transRow2;
    // var chkCnt2 = 0;
    // for(var i = 0 ; i < ds_detail.getRowCount() ; i++){
    //     if (ds_detail.getCellData(i, "choice") == "T"){
    //         var idx = ds_out.getMatchedIndex("bilgClntNo", ds_detail.getCellData(i, "sellClntNo"));
    //         var nameValueRow = 0;
    //         var ablePrc = false;
    //         for(var j = 0 ; j < ds_out.getRowCount() ; j++){
    //             if (ds_detail.getCellData(i, "sellClntNo") == ds_out.getCellData(i, "bilgClntNo") && !ablePrc){
    //                 ablePrc = true;
    //                 nameValueRow = j;
    //             }
    //         }
    //         // if(ds_out.NameValue(ds_out.NameValueRow('bilgClntNo',ds_detail.NameValue(i, "sellClntNo")), "choice") == "T"){
    //         if (ablePrc && ds_out.getCellData(nameValueRow, "choice") == "T"){
    //             // transRow2 = ds_detail.ExportData(i,1,false);
    //             // ds_saveDetail.ImportData(transRow2);
    //             ds_saveDetail.setJSON([ds_detail.getAllJSON()[i]], true);
    //             chkCnt2++;
    //         }
    //     }
    // }
    // scwin.isFilter = true;
    // // gr_detail.DataID = '';
