scwin.sbm_retrieve_submit = function (e) {
    ds_condition.set("adptYm", ica_adptYm.getValue());
    ds_condition.set("qryConDtFm", ica_qryConDtFm.getValue());
    ds_condition.set("qryConDtTo", ica_qryConDtTo.getValue());
    ds_condition.set("homeClntNo", ed_homeClntNo.getValue());
    ds_condition.set("qryConKnd", acb_qryConKnd.getValue());

};

scwin.sbm_retrieve_submitdone = async function (e) {
    // ds_out event=OnLoadCompleted(rowcnt)>
    var rowcnt = ds_out.getRowCount();
    txt_totalRows.setValue(rowcnt);

	if (rowcnt == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
		$c.gus.cfDisableBtn([btn_save, btn_delete]);
	}else if (rowcnt > 0){
		// ds_out.UseFilter = true;

		if (acb_qryConKnd.getValue() == "YM"){
			$c.gus.cfEnableBtnOnly([btn_save]);
			$c.gus.cfDisableBtn([btn_delete]);
		}
		else if (acb_qryConKnd.getValue() == "CERTI"){
			$c.gus.cfEnableBtnOnly([btn_delete]);
			$c.gus.cfDisableBtn([btn_save]);
		}
        gr_out.setFocusedCell(0,0);
        ds_out.setRowPosition(0);

	}

    // ds_detail event=OnLoadCompleted(rowcnt)
    // cfShowTotalRows(totalRows2, rowcnt);

    var rowcnt2 = ds_detail.getRowCount();
    txt_totalRows2.setValue(rowcnt2);

	// gr_detail.DataID = '';
	scwin.ds_detail_OnFilter();
	// gr_detail.DataID = 'ds_detail';

};

